/* Linker version script: the driver exports ONLY the ODBC entry points.
 * Everything else - the protocol core, OpenSSL, libc helpers - is local and
 * invisible to the Driver Manager and the host process. */
SEERODBC_1.0 {
  global:
    SQL*;
  local:
    *;
};
